SELECT DISTINCT u.user_id AS userId, u.user_name AS userName, CONCAT(COALESCE(u.nick_name, u.user_name), '(', COALESCE(u.user_name, ''), ')') AS nickName FROM sys_user u JOIN sys_user_role ur ON u.user_id = ur.user_id JOIN sys_role r ON ur.role_id = r.role_id WHERE r.role_key = #{roleKey}
AND u.dept_id = #{parentDeptId}
ORDER BY u.user_name
